  import React from 'react'
  import { MDXTag } from '@mdx-js/tag'


const layoutProps = {

};
export default class MDXContent extends React.Component {
  constructor(props) {
    super(props)
    this.layout = null
  }
  render() {
    const { components, ...props } = this.props

    return <MDXTag
             name="wrapper"

             components={components}><MDXTag name="h1" components={components} props={{"id":"goncy"}}>{`Goncy`}</MDXTag>
<MDXTag name="p" components={components}><MDXTag name="em" components={components} parentName="p">{`Welcome to the documentation of `}<MDXTag name="em" components={components} parentName="em">{`goncy`}</MDXTag></MDXTag></MDXTag>
<MDXTag name="h3" components={components} props={{"id":"batteries-included"}}>{`Batteries included:`}</MDXTag>
<MDXTag name="p" components={components}>{`🎁 UI components`}</MDXTag>
<MDXTag name="p" components={components}>{`📋 My form solution`}</MDXTag>
<MDXTag name="p" components={components}>{`🛠 Super handy utils`}</MDXTag>
           </MDXTag>
  }
}
MDXContent.isMDXComponent = true
